/* JSで動的に制御（推奨パターン） */
element.addEventListener('mouseenter', () => {
  element.style.willChange = 'transform';
});
element.addEventListener('transitionend', () => {
  element.style.willChange = 'auto'; // 解除
});

/* ⚠️ アンチパターン: 全要素に常時指定 */
/* * { will-change: transform; } ← NG */

/* レイアウト・スタイル・ペイントを封じ込め */
.widget {
  contain: layout style paint;
}

/* 全てのcontainmentを適用（最も強力） */
.isolated {
  contain: strict;
  /* = contain: size layout style paint */
}

/* content-visibility と併用 */
.section {
  contain: content;
  /* = contain: layout style paint（sizeなし） */
  content-visibility: auto;
  contain-intrinsic-size: auto 300px;
}

/* 画面外のセクションは描画しない */
.section {
  content-visibility: auto;
  contain-intrinsic-size: auto 500px; /* 推定サイズ */
}

/* リストアイテムの最適化 */
.list-item {
  content-visibility: auto;
  contain-intrinsic-size: auto 80px;
}

/* 完全に非表示（display:none風だがDOMに残る） */
.hidden-section {
  content-visibility: hidden;
}

// debounce: 最後の呼出しから指定時間後に実行
function debounce(fn, delay) {
  let timer;
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
}

// throttle: 指定間隔で最大1回実行
function throttle(fn, interval) {
  let lastTime = 0;
  return (...args) => {
    const now = Date.now();
    if (now - lastTime >= interval) {
      lastTime = now;
      fn(...args);
    }
  };
}

// 使用例
const handleSearch = debounce((query) => {
  fetch(`/api/search?q=${query}`);
}, 300);

const handleScroll = throttle(() => {
  updateScrollProgress();
}, 100);

input.addEventListener('input', (e) => handleSearch(e.target.value));
window.addEventListener('scroll', handleScroll, { passive: true });

